<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Tooltip Component</title>
  <link rel="stylesheet" href="styles.css">
</head>
<body>
  <button class="relative hover:text-blue-500" id="tooltip-btn">Hover over me</button>
  <div class="absolute hidden bg-red-500 p-2 top-10 right-10" id="tooltip"></div>
  <script src="script.js"></script>
</body>
</html>"}
