  @apply visible;
}"}
script.js: {"text":"// get the button and tooltip elements
const btn = document.getElementById('tooltip-btn');
const tooltip = document.getElementById('tooltip');

// create a function to create the tooltip component
function createTooltip() {
  // show the tooltip
  tooltip.classList.add('visible');
  // add an event listener to hide the tooltip when the user stops hovering
  btn.addEventListener('mouseleave', () => {
    tooltip.classList.remove('visible');
  });
}

// create and show the tooltip on button hover
btn.addEventListener('mouseover', createTooltip);"}
